#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,k,a[N],s[N],q[N],hh,tt,lst[N][210],stk[N],top;
long long f[N][210],y[N];

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        s[i]=s[i-1]+a[i];
    }
    for(int i=1;i<=k;i++){
        hh=1,tt=0;
        for(int j=i+1;j<=n;j++){
            y[j-1]=1ll*s[j-1]*s[j-1]-f[j-1][i-1];
            while(hh<tt && (__int128)(y[q[tt]]-y[q[tt-1]])*(s[j-1]-s[q[tt]])>=(__int128)(y[j-1]-y[q[tt]])*(s[q[tt]]-s[q[tt-1]]))
                tt--;
            q[++tt]=j-1;
            while(hh<tt && (y[q[hh+1]]-y[q[hh]])<=(__int128)s[j]*(s[q[hh+1]]-s[q[hh]])) hh++;
            f[j][i]=f[q[hh]][i-1]+1ll*(s[j]-s[q[hh]])*s[q[hh]];
            lst[j][i]=q[hh];
            // printf("%lld,%d ",f[j][i],lst[j][i]);
        }
        // puts("");
    }
    printf("%lld\n",f[n][k]);
    int p=n;
    for(int i=k;i;i--){
        p=lst[p][i];
        stk[++top]=p;
    }
    while(top)
        printf("%d ",stk[top--]);
    return 0;
}
